-- Q1 こてはし台 空き家
INSERT INTO qa_answers (question_id, body, is_official)
SELECT q.id, 'こてはし台（花見川区）の戸建（土地45坪・築32年・バス便）についてお答えします。【相場の目安】こてはし台の戸建＋土地の成約中央値は㎡約18万円（国交省 実取引）。土地が広め（45坪）のため総額はまとまりますが、バス便・築32年なので㎡単価は抑えめで、実勢は1,500〜2,400万円程度が目安です。正確な額はAI査定（無料）でご確認ください。【売却期間】花見川区のバス便・築古は買い手が限られるため、適正価格なら3〜6ヶ月が目安です。【空き家バンク】自治体が運営する登録制度で、登録は無料で選択肢を広げますが、買い手探しの幅は通常の不動産流通（レインズ）の方が広いことが多く、両方の併用が現実的です。千葉市の空き家相談窓口で登録可否をご確認ください。なお空き家のまま放置し「特定空き家」「管理不全空き家」に指定され勧告を受けると、固定資産税の住宅用地特例（1/6）が外れ税負担が大きく増えるため、早めの判断をおすすめします。（TERRA REALTY スタッフ回答）', true
FROM qa_questions q WHERE q.title = 'こてはし台の実家（空き家）をどうするか。毎月の維持費が家計を圧迫'
AND NOT EXISTS (SELECT 1 FROM qa_answers a WHERE a.question_id = q.id);

-- Q3 土気 農地 市街化調整区域
INSERT INTO qa_answers (question_id, body, is_official)
SELECT q.id, '市街化調整区域の農地（500坪）の処分は、宅地に比べてハードルが高い分野です。3つの方法を整理します。【農地のまま売る】買い手は原則として農業従事者等に限られ、農業委員会の許可（農地法3条）が必要です。市街化調整区域＋農地は需要が限られ、価格も宅地よりかなり安くなります。隣接農家への売却・貸与（利用権設定）が現実的な場合があります。【農地転用して売る】農地法5条の転用許可が必要ですが、市街化調整区域は開発が制限され、特に「農用地区域（青地）」だと転用はほぼ認められません。まず千葉市・農業委員会で農用地区域かどうかをご確認ください。【相続土地国庫帰属制度】2023年4月開始の制度で、一定の要件を満たせば国に引き取ってもらえます。ただし審査があり、負担金（10年分の管理費相当・原則20万円〜）が必要で、境界が明確・担保権がない等の条件があります。いずれも個別性が強いため、まず区域区分の確認から始めるのが確実です。（TERRA REALTY スタッフ回答）', true
FROM qa_questions q WHERE q.title = '土気に相続した農地（500坪）の処分方法がわかりません'
AND NOT EXISTS (SELECT 1 FROM qa_answers a WHERE a.question_id = q.id);

-- Q5 おゆみ野 売却タイミング・学区
INSERT INTO qa_answers (question_id, body, is_official)
SELECT q.id, 'おゆみ野の戸建（4LDK・土地45坪・築20年・鎌取15分）についてお答えします。【相場】おゆみ野の戸建＋土地の成約中央値は㎡約19万円（国交省 実取引）。築20年・ファミリー向けの条件なら、おおむね1,800〜2,800万円程度が目安です。【春と秋どちらが有利か】一般に1〜3月（新年度・入学・転勤の前）が最も買い手が多く動きやすい時期で、次いで9〜11月です。売り出しは準備に2〜3ヶ月かかるため、春の成約を狙うなら年末〜1月、秋なら7〜8月から動くのが目安です。買い手の数では春がやや有利な傾向があります。【学区】人気学区はファミリー層の需要に直結するため「売りやすさ」にプラスに働きます。ただし「いくら上がる」と金額を断定はできません。おゆみ野は学区を重視する買い手が多いエリアなので、好学区は成約スピード・競争力の面で有利と考えてよいです。（TERRA REALTY スタッフ回答）', true
FROM qa_questions q WHERE q.title = 'おゆみ野の自宅を売って住み替えを検討。春と秋どちらが売れやすいですか？'
AND NOT EXISTS (SELECT 1 FROM qa_answers a WHERE a.question_id = q.id);

-- Q7 磯辺 投資マンション 実質利回り
INSERT INTO qa_answers (question_id, body, is_official)
SELECT q.id, '磯辺の投資用マンション（築23年・2K・45㎡・1,100万円・月7万円＝表面7.6%）についてお答えします。【実質利回りの計算】実質利回り＝（年間家賃−年間経費）÷物件価格。年間家賃84万円から、管理費・修繕積立金33.6万円（月2.8万×12）、固定資産税4〜6万円、賃貸管理委託料 約4.2万円（家賃の5%）、空室・原状回復 約7万円（年1ヶ月分）を引くと、手残り（NOI）は約34万円。実質利回りは34÷1,100＝約3.0%です。購入時諸費用（仲介手数料・登記・不動産取得税で物件価格の約7〜10%）を加えた総投資額で見ると約2.8%になります。【相場・需要】磯辺のマンション成約中央値は㎡約22万円（国交省）で、45㎡なら約980万円。1,100万円はやや高めです。京葉線・検見川浜は海浜幕張・千葉みなと通勤の単身需要があり、2Kは単身向きです。【注意】築23年は大規模修繕の時期。修繕積立金の値上げ予定・修繕履歴・積立金残高を重要事項調査報告書で必ず確認してください。投資分析ツールでも試算できます。（TERRA REALTY スタッフ回答）', true
FROM qa_questions q WHERE q.title = '磯辺の中古投資マンション購入検討中。京葉線沿線の利回りは？'
AND NOT EXISTS (SELECT 1 FROM qa_answers a WHERE a.question_id = q.id);

-- Q8 都賀 売却・リフォーム加点
INSERT INTO qa_answers (question_id, body, is_official)
SELECT q.id, '都賀の戸建（4LDK・土地38坪・築25年・徒歩12分・2017年内装リフォーム済）についてお答えします。【相場】都賀の戸建＋土地の成約中央値は㎡約20万円（国交省 実取引）。築25年・徒歩12分・内装リフォーム済の条件なら、おおむね1,800〜2,600万円程度が目安です。築25年は新耐震基準（1981年6月以降）に該当し、住宅ローンが通常どおり組めるため買い手の幅が広いのが強みです。都賀駅はJR総武本線・千葉都市モノレールの2路線が使えます。【リフォームの加点】内装リフォームは「売りやすさ」に寄与しますが、かけた費用がそのまま価格に乗るとは限らず、価格への反映は投資額の5〜7割程度が目安です。むしろ「そのまま住める」という安心感で内見から成約までが早まる効果が大きいです。2017年実施なら設備の新しさをアピール材料にできます。まずAI査定で参考価格を確認してください。（TERRA REALTY スタッフ回答）', true
FROM qa_questions q WHERE q.title = '都賀の一戸建て（築25年・4LDK）の売却価格の目安を知りたい'
AND NOT EXISTS (SELECT 1 FROM qa_answers a WHERE a.question_id = q.id);

-- Q10 幕張本郷 購入 注意点
INSERT INTO qa_answers (question_id, body, is_official)
SELECT q.id, '幕張本郷で中古マンション（2LDK・築15年以内・3,000万円以内）をお探しとのこと。【相場】幕張本郷のマンション成約中央値は㎡約43万円（国交省 実取引）。60〜70㎡なら約2,500〜3,000万円で、ご予算3,000万円以内で十分狙える水準です。JR総武線・京成の2路線で海浜幕張・東京方面に出やすく、実需・賃貸とも底堅いエリアです。【購入時の注意点】①修繕積立金：相場より極端に安い物件は、将来の大規模修繕で一時金徴収や大幅値上げのリスクがあります。長期修繕計画・積立金残高・滞納状況を「重要事項調査報告書」で必ず確認を。②修繕履歴：築15年前後は1回目の大規模修繕を終えた頃。実施済みかを確認。③駐車場：機械式は将来の更新費用がかかります。空き状況も確認を。④管理状態：管理組合がきちんと機能しているか（総会議事録）を見ると安心です。購入ガイドも参考にしてください。（TERRA REALTY スタッフ回答）', true
FROM qa_questions q WHERE q.title = '幕張本郷の中古マンション（築15年以内）を3,000万円以内で探しています'
AND NOT EXISTS (SELECT 1 FROM qa_answers a WHERE a.question_id = q.id);

-- Q11 検見川浜 戸建 売却
INSERT INTO qa_answers (question_id, body, is_official)
SELECT q.id, '検見川浜の戸建（4LDK・土地50坪・築18年・駅徒歩8分・2020年外装塗装済）についてお答えします。【相場】美浜区の埋立地は計画的な街並みで戸建人気が高く、近隣（真砂など）の戸建＋土地の成約中央値は㎡30〜40万円台です（国交省）。土地50坪（約165㎡）は広めのため㎡単価は逓減しますが、駅徒歩8分・築18年・外装メンテ済みという良条件を踏まえると、3,000〜4,500万円程度が一つの目安です（正確な額はAI査定でご確認を）。【エリア特性】検見川浜は海浜公園・計画的な住環境で実需人気が高く、築18年は新耐震・住宅ローン可で買い手の幅が広いのが強みです。広めの戸建を求めるファミリー層に訴求できます。外装塗装済みは「すぐ住める」点で内見時のプラス材料になります。住み替え先が決まっていない場合は、売り先行か買い先行かを先に決めると段取りがスムーズです。（TERRA REALTY スタッフ回答）', true
FROM qa_questions q WHERE q.title = '検見川浜の一戸建て（築18年）を売りたい。海浜エリアの相場は？'
AND NOT EXISTS (SELECT 1 FROM qa_answers a WHERE a.question_id = q.id);

-- Q12 あすみが丘 相続 解体or建物ごと
INSERT INTO qa_answers (question_id, body, is_official)
SELECT q.id, 'あすみが丘の戸建（4LDK・土地50坪・築22年・土気駅バス12分）についてお答えします。【相場】あすみが丘の戸建＋土地の成約中央値は㎡約14万円（国交省 実取引）。バス便・築22年でも、おおむね1,500〜2,400万円程度が目安です。あすみが丘は街並み・教育環境で根強い需要があり、バス便でも売却は可能です。【解体か建物ごとか】築22年は新耐震基準（1981年6月以降）に該当し、建物にまだ価値があり居住可能なので、基本は「建物ごと（現状渡し、または軽微なリフォーム）」での売却がおすすめです。解体は、更地にすると固定資産税の住宅用地特例（1/6）が外れて税額が上がるうえ、解体費が100〜200万円かかるため、建物が使えるうちは不要なことが多いです。外観に問題がないとのことなので、現状渡しで売りやすい状態です。まずAI査定で目安を確認してください。（TERRA REALTY スタッフ回答）', true
FROM qa_questions q WHERE q.title = 'あすみが丘の一戸建て（築22年）を相続。バス便エリアでも売れますか？'
AND NOT EXISTS (SELECT 1 FROM qa_answers a WHERE a.question_id = q.id);

-- Q13 みつわ台 空き家 解体収支
INSERT INTO qa_answers (question_id, body, is_official)
SELECT q.id, 'みつわ台の空き家（3LDK・土地42坪・延床95㎡・築35年・バス便）の収支を整理します。【土地として売る場合】みつわ台の土地の成約中央値は㎡約12万円（国交省 実取引）。土地42坪（約139㎡）なら土地価格は約1,400〜1,700万円が目安です。【解体費】木造・延床95㎡（約29坪）の解体費は約100〜180万円が目安。【差引収支の例】土地売却 約1,400〜1,700万円 − 解体費 約100〜180万円 ＝ 手取り 約1,250〜1,550万円（このほか仲介手数料・境界確定の測量費30〜60万円が別途）。【先に解体すべきか】必ずしも先に解体する必要はありません。築35年でも「古家付き土地」として現状のまま売り出せば、建替え前提の買主が解体費を負担してくれるケースがあります。先に解体して更地にすると住宅用地特例（1/6）が外れ固定資産税が上がるため、まず古家付きで売り出し反応を見るのが無難です。（TERRA REALTY スタッフ回答）', true
FROM qa_questions q WHERE q.title = 'みつわ台の空き家、固定資産税が年12万円。売れるまでの維持が限界です'
AND NOT EXISTS (SELECT 1 FROM qa_answers a WHERE a.question_id = q.id);

-- Q15 院内 特定空き家
INSERT INTO qa_answers (question_id, body, is_official)
SELECT q.id, '院内町（中央区）の古家（築45年・木造・土地40坪・空き家5年）についてお答えします。【特定空き家と税金】空家等対策特別措置法に基づき「特定空き家」に指定され、市から助言・勧告を受けると、固定資産税の住宅用地特例（1/6）が解除され、土地の税負担が大きく増えます（都市計画税も含め実質的に数倍）。2023年の法改正で、その前段階の「管理不全空き家」も勧告の対象に加わりました。【今からでも間に合うか】指定は自動ではなく、市の調査・手続を経て行われます。勧告を受ける前に、適切な管理・売却・解体のいずれかで対応すれば回避できますので、早めに動けば十分間に合います。【おすすめ】中央区院内は千葉駅に近い好立地で、戸建＋土地の成約水準は㎡30万円台と高めです（国交省・サンプルは少なめ）。築45年木造でも「古家付き土地」として需要が見込めます。税負担の回避と資産活用の両面から、早期の売却が有利です。まず千葉市の空き家相談窓口に相談しつつ、古家付き土地で査定を取ることをおすすめします。（TERRA REALTY スタッフ回答）', true
FROM qa_questions q WHERE q.title = '院内町の古家（築45年）を空き家のまま5年間放置してしまいました'
AND NOT EXISTS (SELECT 1 FROM qa_answers a WHERE a.question_id = q.id);

-- Q16 八千代台 旧耐震 相続
INSERT INTO qa_answers (question_id, body, is_official)
SELECT q.id, '八千代台（花見川区）の戸建（4LDK・土地40坪・築43年・1980年建築・バス8分）についてお答えします。【旧耐震でも売れるか】1981年5月以前の建築確認は「旧耐震基準」で、住宅ローンが付きにくい（フラット35は耐震基準適合が要件）ため、買い手は①現金購入②建替え・解体前提の買主が中心になります。それでも売却は可能で、価格は建物価値ほぼゼロ＋土地値が中心になります。【解体して土地として売る場合】木造・延床105㎡（約32坪）の解体費は約120〜200万円。土地40坪（約132㎡）で、花見川区のバス便エリアの土地単価（こてはし台で土地中央値 約10万円/㎡前後・国交省）を踏まえると、土地は約1,300〜2,000万円が目安です。【おすすめ】いきなり解体せず、まず「古家付き土地（解体は買主負担）」で売り出すのが無難です。建替え前提の買主が付けば解体費を負担せずに済みます。なお物件の所在地（花見川区側）の用途地域・再建築可否を事前に確認してください。（TERRA REALTY スタッフ回答）', true
FROM qa_questions q WHERE q.title = '八千代台の築40年戸建てを相続。旧耐震基準でも売れますか？'
AND NOT EXISTS (SELECT 1 FROM qa_answers a WHERE a.question_id = q.id);

-- Q18 幕張タワマン 売却タイミング・税
INSERT INTO qa_answers (question_id, body, is_official)
SELECT q.id, '幕張のタワーマンション（2LDK・70㎡・25階・築8年・購入2,800万円・査定3,400〜3,600万円）についてお答えします。【相場感】幕張ベイタウンのタワーは人気が高く、近隣のマンション成約は㎡50〜60万円台（国交省）。査定3,500万円÷70㎡＝㎡50万円は妥当で、約600〜800万円の含み益が出ています。【税の重要ポイント】自己居住中であれば、売却時に「居住用財産の3,000万円特別控除」が使える可能性が高く、その場合は含み益600〜800万円は控除内に収まり、譲渡所得税が実質ゼロになることが多いです。ただし、賃貸に出すと自己居住用でなくなり、住まなくなってから3年を経過する年の年末を過ぎると、この特別控除が使えなくなります。つまり「売る」なら特例が使える今のうちが税制上有利です。【判断】高層・海側・築浅・幕張新都心は流動性が高く売りやすい条件です。転勤で空けるなら、特例が使え、二重ローンや管理の手間も避けられる「売却」が合理的なケースが多いです。プレミアムの有無は、同じマンション内の直近の成約事例で確認しましょう。（TERRA REALTY スタッフ回答）', true
FROM qa_questions q WHERE q.title = '幕張のタワーマンション（25階・築8年）の売却タイミング。今が売り時ですか？'
AND NOT EXISTS (SELECT 1 FROM qa_answers a WHERE a.question_id = q.id);

-- Q20 千城台 団地 建替え決議
INSERT INTO qa_answers (question_id, body, is_official)
SELECT q.id, '千城台の団地（3DK・55㎡・5階・築48年・管理費1.5万＋積立0.85万＝月2.3万円・旧耐震）について正直にお答えします。【相場】築48年・旧耐震・エレベーターの有無で評価が分かれますが、千城台の築古団地の実勢は数百万円台（おおむね200〜600万円）が現実的です。建物価値はほぼゼロで、旧耐震＋築48年は住宅ローンがほぼ付かないため、買い手は現金客が中心になります。【売却期間】買い手が限られるため、適正（低め）の価格設定で3〜6ヶ月、強気だと長期化します。【建替え決議を待つべきか】マンションの建替えは区分所有法で組合員の5分の4以上の賛成が必要です。築48年でも建替えが実現する団地はごく一部で、合意形成に何年もかかり、実現しないことも多いのが実情です。実現しても各戸に数百万円規模の追加負担金が生じるのが一般的です。待つ間も管理費・積立金 月2.3万円（年約28万円）の負担が続くため、「待てば必ず得」とは限りません。早期売却と比較したうえでの判断をおすすめします。（TERRA REALTY スタッフ回答）', true
FROM qa_questions q WHERE q.title = '千城台の団地（築48年）を売りたい。管理費が月2万円で維持できません'
AND NOT EXISTS (SELECT 1 FROM qa_answers a WHERE a.question_id = q.id);

-- 確認：回答付き質問の件数（20件すべてに回答が付くはず）
SELECT count(DISTINCT question_id) AS answered_questions FROM qa_answers;
